/** Plain-text fallback when DiffView paints zero height. */
function previewLinesFallback(
  lines: DiffLineData[],
  theme: ReturnType<typeof useHostTheme>,
) {
  const maxLine = lines.reduce(
    (m, l, i) => Math.max(m, l.lineNumber ?? i + 1),
    0,
  );
  const gutterW = Math.max(4, String(maxLine).length);
  return (
    <div
      style={{
        margin: 0,
        padding: "6px 10px",
        fontFamily: MONO_FONT,
        fontSize: 12,
        lineHeight: "18px",
        color: theme.text.primary,
        whiteSpace: "pre",
        tabSize: 2,
      }}
    >
      {lines.map((line, i) => {
        const n = line.lineNumber ?? i + 1;
        const gutter = String(n).padStart(gutterW, " ");
        const accent =
          line.type === "added"
            ? theme.accent.primary
            : line.type === "removed"
              ? "#f14c4c"
              : theme.text.primary;
        return (
          <div
            key={`${n}-${i}`}
            style={{
              display: "flex",
              background:
                line.type === "added"
                  ? "color-mix(in srgb, var(--canvas-accent, #3794ff) 12%, transparent)"
                  : undefined,
            }}
          >
            <span
              style={{
                flexShrink: 0,
                width: `${gutterW + 2}ch`,
                paddingRight: 8,
                color: theme.text.tertiary,
                textAlign: "right",
                userSelect: "none",
              }}
            >
              {gutter}
            </span>
            <span style={{ color: accent, minWidth: 0 }}>{line.content}</span>
          </div>
        );
      })}
    </div>
  );
}

function PreviewDiffContent({
  path,
  lines,
  theme,
}: {
  path: string;
  lines: DiffLineData[];
  theme: ReturnType<typeof useHostTheme>;
}) {
  const wrapRef = useRef<HTMLDivElement | null>(null);
  const [useFallback, setUseFallback] = useState(false);
  const language = languageFromPath(path);

  useEffect(() => {
    if (lines.length === 0) return;
    setUseFallback(false);
    let cancelled = false;
    const measure = () => {
      const el = wrapRef.current;
      if (!el || cancelled) return;
      const painted =
        el.scrollHeight > 8 || el.getBoundingClientRect().height > 8;
      setUseFallback(!painted);
    };
    // Keep DiffView mounted; only commit fallback after it had time to paint.
    const t1 = window.setTimeout(measure, 120);
    const t2 = window.setTimeout(measure, 400);
    const el = wrapRef.current;
    const ro = el ? new ResizeObserver(measure) : null;
    if (el && ro) ro.observe(el);
    return () => {
      cancelled = true;
      window.clearTimeout(t1);
      window.clearTimeout(t2);
      ro?.disconnect();
    };
  }, [path, lines]);

  return (
    <div style={{ width: "100%", position: "relative" }}>
      <div
        ref={wrapRef}
        style={
          useFallback
            ? {
                position: "absolute",
                left: 0,
                right: 0,
                opacity: 0,
                pointerEvents: "none",
                width: "100%",
              }
            : { width: "100%" }
        }
        aria-hidden={useFallback || undefined}
      >
        <DiffView
          path={path}
          language={language}
          lines={lines}
          showLineNumbers
          showAccentStrip
          style={{ width: "100%" }}
        />
      </div>
      {useFallback ? previewLinesFallback(lines, theme) : null}
    </div>
  );
}

function CodePreviewModal({
  file,
  theme,
  onClose,
  onOpenInIde,
}: {
  file: FileRef;
  theme: ReturnType<typeof useHostTheme>;
  onClose: () => void;
  onOpenInIde: (ref: FileRef) => void;
}) {
  const dialogRef = useRef<HTMLDivElement | null>(null);
  const viewportRef = useRef<HTMLDivElement | null>(null);
  const contentRef = useRef<HTMLDivElement | null>(null);
  const offsetRef = useRef(0);
  const userScrolledRef = useRef(false);
  const [offset, setOffset] = useState(0);
  const [viewportH, setViewportH] = useState(560);
  const [contentH, setContentH] = useState(0);
  const content = FILE_CONTENTS[file.path];
  const { start, end } = highlightRange(file);
  const lines = useMemo(
    () =>
      content
        ? fileToPreviewLines(content, start, end, { windowLargeFiles: true })
        : fileToPreviewLines(
            "// File contents were not embedded for this path.\n// Use the open-in-IDE control to view it in the editor.",
          ),
    [content, start, end],
  );
  const maxOffset = Math.max(0, contentH - viewportH);

  const applyOffset = (next: number) => {
    const clamped = Math.max(0, Math.min(maxOffset, next));
    offsetRef.current = clamped;
    setOffset(clamped);
  };

  // New file / focus target: clear scroll so stale offsets cannot leak.
  useEffect(() => {
    userScrolledRef.current = false;
    offsetRef.current = 0;
    setOffset(0);
    setContentH(0);
  }, [file.path, start]);

  // Pixel viewport height so flex children can shrink and scroll.
  useEffect(() => {
    function measureShell() {
      const shell = dialogRef.current?.querySelector(
        "[data-map-preview]",
      ) as HTMLElement | null;
      if (!shell) return;
      const shellH = shell.getBoundingClientRect().height;
      // header ~40 + optional missing-content callout + padding
      const chrome = !content ? 100 : 52;
      setViewportH(Math.max(200, Math.floor(shellH - chrome)));
    }
    measureShell();
    window.addEventListener("resize", measureShell);
    return () => window.removeEventListener("resize", measureShell);
  }, [content, file.path]);

  useEffect(() => {
    const el = contentRef.current;
    if (!el) return;
    const measure = () => setContentH(el.getBoundingClientRect().height);
    measure();
    const ro = new ResizeObserver(measure);
    ro.observe(el);
    return () => ro.disconnect();
  }, [file.path, lines]);

  // Jump to focus while the user has not scrolled; ignore remeasures after wheel.
  useEffect(() => {
    if (userScrolledRef.current || start == null || contentH <= 0) return;
    const lineH = contentH / Math.max(1, lines.length);
    const focusIdx = lines.findIndex(
      (l) => l.lineNumber != null && l.lineNumber >= start,
    );
    const next =
      focusIdx >= 0
        ? Math.max(0, focusIdx * lineH - 72)
        : Math.max(0, (start - 1) * lineH - 72);
    applyOffset(next);
  }, [file.path, start, contentH, lines.length, maxOffset]);

  // Wheel → translateY; avoids overflow/scrollTop in canvas hosts.
  useEffect(() => {
    const dialog = dialogRef.current;
    const viewport = viewportRef.current;
    if (!dialog || !viewport) return;
    const onWheel = (e: WheelEvent) => {
      const path = typeof e.composedPath === "function" ? e.composedPath() : [];
      const over =
        path.includes(viewport) ||
        (e.target instanceof Node && viewport.contains(e.target));
      if (!over) return;
      e.preventDefault();
      e.stopImmediatePropagation();
      userScrolledRef.current = true;
      applyOffset(offsetRef.current + e.deltaY);
    };
    dialog.addEventListener("wheel", onWheel, { passive: false, capture: true });
    return () =>
      dialog.removeEventListener("wheel", onWheel, {
        capture: true,
      } as EventListenerOptions);
  }, [file.path, maxOffset, viewportH, contentH]);

  useEffect(() => {
    function onKey(e: KeyboardEvent) {
      if (e.key === "Escape") onClose();
    }
    window.addEventListener("keydown", onKey);
    return () => window.removeEventListener("keydown", onKey);
  }, [onClose]);

  const footerCallout = !content ? (
    <Callout tone="info" style={{ margin: 8 }}>
      Contents not embedded. Open in editor for the full file.
    </Callout>
  ) : null;

  const modalH =
    typeof window !== "undefined"
      ? Math.min(window.innerHeight * 0.8, 900)
      : 720;

  return (
    <div
      ref={dialogRef}
      role="dialog"
      aria-modal="true"
      aria-label={refPathLabel(file)}
      onClick={onClose}
      style={{
        position: "fixed",
        inset: 0,
        zIndex: 1000,
        background: "color-mix(in srgb, transparent 45%, black)",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        padding: 24,
      }}
    >
      <div
        data-map-preview
        onClick={(e: { stopPropagation(): void }) => e.stopPropagation()}
        style={{
          width: "min(920px, 100%)",
          height: modalH,
          maxHeight: modalH,
          display: "flex",
          flexDirection: "column",
          overflow: "hidden",
          background: theme.bg.elevated,
          border: `1px solid ${theme.stroke.primary}`,
          borderRadius: 8,
        }}
      >
        <div
          style={{
            flexShrink: 0,
            display: "flex",
            alignItems: "center",
            gap: 8,
            minHeight: 40,
            padding: "6px 10px",
            borderBottom: `1px solid ${theme.stroke.tertiary}`,
            fontSize: 12,
            fontWeight: 600,
            color: theme.text.primary,
          }}
        >
          <span
            style={{
              flex: 1,
              minWidth: 0,
              overflow: "hidden",
              textOverflow: "ellipsis",
              whiteSpace: "nowrap",
            }}
          >
            {refPathLabel(file)}
          </span>
          <IconButton title="Open in editor" onClick={() => onOpenInIde(file)}>
            <OpenExternalIcon />
          </IconButton>
          <Button variant="ghost" onClick={onClose}>
            Close
          </Button>
        </div>
        <div
          ref={viewportRef}
          data-map-preview-scroll
          data-map-preview-line-count={lines.length}
          style={{
            height: viewportH,
            overflow: "hidden",
            position: "relative",
            background: theme.bg.editor,
            flexShrink: 0,
          }}
        >
          <div
            ref={contentRef}
            style={{
              transform: `translateY(${-offset}px)`,
              willChange: "transform",
              width: "100%",
            }}
          >
            <PreviewDiffContent
              path={file.path}
              lines={lines}
              theme={theme}
            />
          </div>
        </div>
        {footerCallout}
      </div>
    </div>
  );
}


function relPath(abs: string): string {
  return abs.startsWith(`${ROOT}/`) ? abs.slice(ROOT.length + 1) : abs;
}

function fileRefKey(ref: FileRef): string {
  return `${ref.path}:${ref.line ?? 0}`;
}

function collectFiles(entity: {
  files: FileRef[];
  body: DocBlock[];
}): FileRef[] {
  const seen = new Set<string>();
  const out: FileRef[] = [];
  for (const f of entity.files) {
    const k = fileRefKey(f);
    if (!seen.has(k)) {
      seen.add(k);
      out.push(f);
    }
  }
  for (const b of entity.body) {
    if (b.type === "code") {
      const f = fileRef(b.ref);
      const k = fileRefKey(f);
      if (!seen.has(k)) {
        seen.add(k);
        out.push(f);
      }
    }
  }
  return out;
}

type TreeFile = {
  kind: "file";
  name: string;
  relPath: string;
  absPath: string;
};

type TreeDir = {
  kind: "dir";
  name: string;
  children: Map<string, TreeFile | TreeDir>;
};

function buildTree(absPaths: string[]): TreeDir {
  const root: TreeDir = { kind: "dir", name: "", children: new Map() };
  for (const abs of absPaths) {
    const rel = relPath(abs);
    const segments = rel.split("/");
    let current = root;
    for (let i = 0; i < segments.length; i++) {
      const seg = segments[i];
      const isFile = i === segments.length - 1;
      if (isFile) {
        current.children.set(seg, {
          kind: "file",
          name: seg,
          relPath: rel,
          absPath: abs,
        });
      } else {
        let child = current.children.get(seg);
        if (!child || child.kind === "file") {
          child = { kind: "dir", name: seg, children: new Map() };
          current.children.set(seg, child);
        }
        current = child;
      }
    }
  }
  return root;
}

/** File tree paths — prefer generated MAP_PATHS (from `bun update.ts`). */
function collectAllMapPaths(): string[] {
  if (MAP_PATHS.length > 0) return [...MAP_PATHS];
  // Fallback before first update: derive from FILE_MAP directly.
  return [
    ...new Set(Object.values(FILE_MAP).map((r) => r.path)),
  ].sort((a, b) => a.localeCompare(b));
}

function countFiles(dir: TreeDir): number {
  let n = 0;
  for (const child of dir.children.values()) {
    if (child.kind === "file") n++;
    else n += countFiles(child);
  }
  return n;
}

function dirShouldExpand(dirRelPath: string, hoverPaths: string[]): boolean {
  return hoverPaths.some(
    (p) => p === dirRelPath || p.startsWith(`${dirRelPath}/`),
  );
}

function dirIsExpanded(
  dirRelPath: string,
  activePaths: string[],
  userExpanded: Record<string, boolean>,
): boolean {
  if (dirRelPath in userExpanded) {
    return userExpanded[dirRelPath];
  }
  return activePaths.length > 0 && dirShouldExpand(dirRelPath, activePaths);
}

function clearCollapsedAncestorsOfPaths(
  prev: Record<string, boolean>,
  activePaths: string[],
): Record<string, boolean> {
  let next: Record<string, boolean> | null = null;
  for (const path of activePaths) {
    const segments = path.split("/");
    for (let i = 1; i < segments.length; i++) {
      const ancestor = segments.slice(0, i).join("/");
      if (prev[ancestor] === false) {
        if (!next) next = { ...prev };
        delete next[ancestor];
      }
    }
  }
  return next ?? prev;
}

function leavePreview(
  e: {
    relatedTarget: EventTarget | null;
    currentTarget: EventTarget & { contains(node: Node): boolean };
  },
  onClearPreview: () => void,
) {
  const next = e.relatedTarget;
  if (next instanceof Node && e.currentTarget.contains(next)) return;
  onClearPreview();
}

function sidebarType(width: number) {
  const t = clamp((width - MIN_SIDEBAR_W) / (MAX_SIDEBAR_W - MIN_SIDEBAR_W), 0, 1);
  return {
    title: 14 + t * 6,
    body: 12 + t * 4,
    meta: 11 + t * 3,
    code: 11 + t * 3,
    gap: 10 + t * 6,
    pad: 12 + t * 8,
  };
}

function codeToDiffLines(code: string, startLine?: number): DiffLineData[] {
  const lines = code.replace(/\n$/, "").split("\n");
  return lines.map((content, idx) => ({
    type: "unchanged" as const,
    content,
    ...(startLine != null ? { lineNumber: startLine + idx } : {}),
  }));
}

function renderDocBlocks(
  blocks: DocBlock[],
  typeScale: ReturnType<typeof sidebarType>,
  theme: ReturnType<typeof useHostTheme>,
  previewFile: (ref: FileRef) => void,
  onPreviewFiles?: (refs: FileRef[]) => void,
  onClearPreview?: () => void,
): ReactNode {
  return (
    <Stack gap={typeScale.gap}>
      {blocks.map((block, i) => {
        switch (block.type) {
          case "prose":
            return (
              <Text
                key={i}
                style={{
                  fontSize: typeScale.body,
                  lineHeight: 1.45,
                  color: theme.text.secondary,
                }}
              >
                {richInline(block.text)}
              </Text>
            );
          case "code": {
            const key = block.ref;
            const file = fileRef(key);
            const code = snippet(key);
            const lines = codeToDiffLines(code, file.line);
            return (
              <div
                key={i}
                onMouseEnter={() => onPreviewFiles?.([file])}
                onMouseLeave={(e: {
                  currentTarget: EventTarget & { contains(n: Node): boolean };
                  relatedTarget: EventTarget | null;
                }) => {
                  if (onClearPreview) leavePreview(e, onClearPreview);
                }}
              >
                <Stack gap={4}>
                  <Button
                    variant="ghost"
                    onClick={() => previewFile(file)}
                    style={{
                      justifyContent: "flex-start",
                      height: "auto",
                      minHeight: 0,
                      padding: "2px 4px",
                    }}
                  >
                    <Text
                      style={{
                        fontFamily: MONO_FONT,
                        color: theme.text.link,
                        fontSize: typeScale.code,
                        textAlign: "left",
                      }}
                    >
                      {refPathLabel(file)}
                    </Text>
                  </Button>
                  {block.caption ? (
                    <Text
                      style={{
                        fontSize: typeScale.meta,
                        color: theme.text.tertiary,
                        lineHeight: 1.35,
                      }}
                    >
                      {block.caption}
                    </Text>
                  ) : null}
                  <div
                    role="button"
                    tabIndex={0}
                    title="Preview full file"
                    onClick={() => previewFile(file)}
                    onKeyDown={(e: { key: string; preventDefault(): void }) => {
                      if (e.key === "Enter" || e.key === " ") {
                        e.preventDefault();
                        previewFile(file);
                      }
                    }}
                    style={{ cursor: "pointer" }}
                  >
                    <Card style={{ overflow: "hidden" }}>
                      <CardHeader>{refPathLabel(file)}</CardHeader>
                      <CardBody style={{ padding: 0 }}>
                        <div
                          data-map-code-scroll
                          onWheel={(e: {
                            stopPropagation(): void;
                          }) => {
                            e.stopPropagation();
                          }}
                          style={{
                            backgroundColor: theme.bg.editor,
                            maxHeight: 280,
                            overflow: "auto",
                            minHeight: 0,
                          }}
                        >
                          <DiffView
                            path={file.path}
                            lines={lines}
                            showLineNumbers={file.line != null}
                            showAccentStrip={false}
                          />
                        </div>
                      </CardBody>
                    </Card>
                  </div>
                </Stack>
              </div>
            );
          }
          default: {
            const _exhaustive: never = block;
            return _exhaustive;
          }
        }
      })}
    </Stack>
  );
}

function layoutWrappedPath(pathIds: string[]): {
  nodes: LaidOutNode[];
  width: number;
  height: number;
} {
  const nodes = pathIds.map((id, i) => {
    const row = Math.floor(i / COLS);
    const iInRow = i % COLS;
    const rtl = row % 2 === 1;
    const col = rtl ? COLS - 1 - iInRow : iInRow;
    return {
      id,
      x: PAD + col * (NODE_W + GAP_X),
      y: PAD + row * (NODE_H + GAP_Y),
      row,
      col,
      rtl,
    };
  });
  const rows = Math.ceil(pathIds.length / COLS);
  const width = PAD * 2 + COLS * NODE_W + (COLS - 1) * GAP_X;
  const height =
    PAD * 2 + rows * NODE_H + Math.max(0, rows - 1) * GAP_Y;
  return { nodes, width, height };
}

function sideAnchor(
  n: LaidOutNode,
  side: "left" | "right" | "top" | "bottom",
): { x: number; y: number } {
  const cx = n.x + NODE_W / 2;
  const cy = n.y + NODE_H / 2;
  if (side === "left") return { x: n.x, y: cy };
  if (side === "right") return { x: n.x + NODE_W, y: cy };
  if (side === "top") return { x: cx, y: n.y };
  return { x: cx, y: n.y + NODE_H };
}

function buildPathEdges(
  laidOut: LaidOutNode[],
  edgeMeta: Map<string, MapEdge>,
): LaidOutEdge[] {
  const edges: LaidOutEdge[] = [];
  for (let i = 0; i < laidOut.length - 1; i++) {
    const from = laidOut[i];
    const to = laidOut[i + 1];
    const key = edgeKey(from.id, to.id);
    const meta = edgeMeta.get(key);
    const wrap = from.row !== to.row;
    if (wrap) {
      const s = sideAnchor(from, "bottom");
      const t = sideAnchor(to, "top");
      const midY = (s.y + t.y) / 2;
      edges.push({
        key,
        from: from.id,
        to: to.id,
        sourceX: s.x,
        sourceY: s.y,
        targetX: t.x,
        targetY: t.y,
        kind: "wrap",
        label: meta?.label ?? "",
        labelX: s.x + 18,
        labelY: midY,
      });
    } else {
      const forward = !from.rtl;
      const s = sideAnchor(from, forward ? "right" : "left");
      const t = sideAnchor(to, forward ? "left" : "right");
      const midX = (s.x + t.x) / 2;
      const midY = (s.y + t.y) / 2;
      edges.push({
        key,
        from: from.id,
        to: to.id,
        sourceX: s.x,
        sourceY: s.y,
        targetX: t.x,
        targetY: t.y,
        kind: "along",
        label: meta?.label ?? "",
        labelX: midX,
        labelY: midY - 22,
      });
    }
  }
  return edges;
}

function edgePath(e: LaidOutEdge): string {
  if (e.kind === "wrap") {
    const midY = (e.sourceY + e.targetY) / 2;
    return `M ${e.sourceX} ${e.sourceY} L ${e.sourceX} ${midY} L ${e.targetX} ${midY} L ${e.targetX} ${e.targetY}`;
  }
  const mx = (e.sourceX + e.targetX) / 2;
  return `M ${e.sourceX} ${e.sourceY} C ${mx} ${e.sourceY}, ${mx} ${e.targetY}, ${e.targetX} ${e.targetY}`;
}

/** Dense tree row height (CollapsibleSection is too tall here). */
const TREE_ROW_H = 18;
const TREE_INDENT = 12;

function renderTreeDir(
  dir: TreeDir,
  dirRelPath: string,
  depth: number,
  selectedPaths: string[],
  hoverPaths: string[],
  activePaths: string[],
  userExpanded: Record<string, boolean>,
  onToggleDir: (dirRelPath: string) => void,
  theme: ReturnType<typeof useHostTheme>,
  previewFile: (ref: FileRef) => void,
  typeScale: ReturnType<typeof sidebarType>,
): ReactNode {
  const treeLabelSize = Math.max(11, typeScale.body - 1);
  const entries = [...dir.children.entries()].sort((a, b) => {
    const aDir = a[1].kind === "dir";
    const bDir = b[1].kind === "dir";
    if (aDir !== bDir) return aDir ? -1 : 1;
    return a[0].localeCompare(b[0]);
  });
  const rowPadLeft = depth * TREE_INDENT + 4;

  return entries.map(([name, entry]) => {
    if (entry.kind === "dir") {
      const childDirPath = dirRelPath ? `${dirRelPath}/${name}` : name;
      const expanded = dirIsExpanded(childDirPath, activePaths, userExpanded);
      const fileCount = countFiles(entry);

      return (
        <div key={childDirPath}>
          <div
            role="button"
            tabIndex={0}
            onClick={(e) => {
              e.stopPropagation();
              onToggleDir(childDirPath);
            }}
            onKeyDown={(e) => {
              if (e.key === "Enter" || e.key === " ") {
                e.preventDefault();
                e.stopPropagation();
                onToggleDir(childDirPath);
              }
            }}
            style={{
              display: "flex",
              alignItems: "center",
              gap: 4,
              height: TREE_ROW_H,
              paddingLeft: rowPadLeft,
              paddingRight: 4,
              boxSizing: "border-box",
              fontFamily: MONO_FONT,
              fontSize: treeLabelSize,
              lineHeight: 1,
              color: theme.text.secondary,
              cursor: "pointer",
              borderRadius: 2,
            }}
          >
            <span
              style={{
                width: 10,
                flexShrink: 0,
                fontSize: 10,
                lineHeight: 1,
                color: theme.text.tertiary,
              }}
            >
              {expanded ? "▾" : "▸"}
            </span>
            <Text
              style={{
                flex: 1,
                minWidth: 0,
                fontFamily: MONO_FONT,
                fontSize: treeLabelSize,
                lineHeight: 1,
                color: theme.text.primary,
                overflow: "hidden",
                textOverflow: "ellipsis",
                whiteSpace: "nowrap",
              }}
            >
              {name}
            </Text>
            <Text
              style={{
                fontSize: 10,
                lineHeight: 1,
                color: theme.text.quaternary,
                flexShrink: 0,
              }}
            >
              {fileCount}
            </Text>
          </div>
          {expanded
            ? renderTreeDir(
                entry,
                childDirPath,
                depth + 1,
                selectedPaths,
                hoverPaths,
                activePaths,
                userExpanded,
                onToggleDir,
                theme,
                previewFile,
                typeScale,
              )
            : null}
        </div>
      );
    }

    const isSelected = selectedPaths.includes(entry.relPath);
    const isHovered = hoverPaths.includes(entry.relPath);
    const highlighted = isSelected || isHovered;

    return (
      <div
        key={entry.relPath}
        role="button"
        tabIndex={0}
        onClick={() => previewFile({ path: entry.absPath })}
        onKeyDown={(e) => {
          if (e.key === "Enter" || e.key === " ") {
            e.preventDefault();
            previewFile({ path: entry.absPath });
          }
        }}
        style={{
          display: "flex",
          alignItems: "center",
          height: TREE_ROW_H,
          paddingLeft: rowPadLeft,
          paddingRight: 4,
          boxSizing: "border-box",
          borderRadius: 2,
          cursor: "pointer",
          lineHeight: 1,
          background: isSelected
            ? theme.fill.secondary
            : isHovered
              ? theme.fill.tertiary
              : "transparent",
          borderLeft: highlighted
            ? `2px solid ${theme.accent.primary}`
            : "2px solid transparent",
        }}
      >
        <Text
          style={{
            fontFamily: MONO_FONT,
            fontSize: treeLabelSize,
            color: highlighted ? theme.accent.primary : theme.text.link,
            overflow: "hidden",
            textOverflow: "ellipsis",
            whiteSpace: "nowrap",
            fontWeight: isSelected ? 600 : undefined,
            lineHeight: 1,
          }}
        >
          {name}
        </Text>
      </div>
    );
  });
}

function BuiltinFileTreePanel({
  files,
  selectedPaths,
  hoverPaths,
  theme,
  height,
  width,
  previewFile,
}: {
  files: { relPath: string; absPath: string }[];
  selectedPaths: string[];
  hoverPaths: string[];
  theme: ReturnType<typeof useHostTheme>;
  height: number;
  width: number;
  previewFile: (ref: FileRef) => void;
}) {
  const tree = buildTree(files.map((f) => f.absPath));
  const typeScale = sidebarType(width);
  const [userExpanded, setUserExpanded] = useCanvasState<Record<string, boolean>>(
    "treeUserExpanded",
    {},
  );
  const activePaths = useMemo(
    () => [...new Set([...selectedPaths, ...hoverPaths])],
    [selectedPaths, hoverPaths],
  );

  useEffect(() => {
    if (activePaths.length === 0) return;
    setUserExpanded((prev) => clearCollapsedAncestorsOfPaths(prev, activePaths));
  }, [activePaths, setUserExpanded]);

  const onToggleDir = useCallback(
    (dirRelPath: string) => {
      setUserExpanded((prev) => {
        const expanded = dirIsExpanded(dirRelPath, activePaths, prev);
        return { ...prev, [dirRelPath]: !expanded };
      });
    },
    [activePaths, setUserExpanded],
  );

  return (
    <aside
      style={{
        width,
        flexShrink: 0,
        boxSizing: "border-box",
        height,
        overflow: "auto",
        borderRadius: 0,
        border: "none",
        background: "transparent",
        display: "flex",
        flexDirection: "column",
        gap: 0,
        padding: "2px 2px",
      }}
    >
      <div data-map-tree-scroll style={{ flex: 1, minHeight: 0 }}>
        {renderTreeDir(
          tree,
          "",
          0,
          selectedPaths,
          hoverPaths,
          activePaths,
          userExpanded,
          onToggleDir,
          theme,
          previewFile,
          typeScale,
        )}
      </div>
    </aside>
  );
}

function FileTreePanel(props: {
  files: { relPath: string; absPath: string }[];
  selectedPaths: string[];
  hoverPaths: string[];
  theme: ReturnType<typeof useHostTheme>;
  height: number;
  width: number;
  previewFile: (ref: FileRef) => void;
}) {
  // Canvas SDK has no FileTreePanel export — always use the inlined builtin.
  // (Bun host maps optionally swap in @pierre/trees via ./host.)
  return <BuiltinFileTreePanel {...props} />;
}

/** Intrinsic SVG size from viewBox — needed so pan/zoom isn't fighting width=100%. */
function svgWorldSize(svg: string): { w: number; h: number } {
  const m = svg.match(/viewBox="([^"]+)"/);
  if (!m) return { w: 800, h: 600 };
  const parts = m[1].trim().split(/[\s,]+/).map(Number);
  const w = parts[2];
  const h = parts[3];
  if (!Number.isFinite(w) || !Number.isFinite(h) || w <= 0 || h <= 0) {
    return { w: 800, h: 600 };
  }
  return { w, h };
}

function svgForCamera(svg: string, w: number, h: number): string {
  return svg
    .replace(/\swidth="[^"]*"/, ` width="${w}"`)
    .replace(/\sheight="[^"]*"/, ` height="${h}"`);
}

function cssEscapeAttr(value: string): string {
  return value.replace(/\\/g, "\\\\").replace(/"/g, '\\"');
}

/** Pointer cursor on hotspot shapes + accent stroke on the focused hotspot. */
function svgWithHotspotChrome(
  svg: string,
  hotspots: ArchHotspot[],
  activeLabels: string[],
  accent: string,
): string {
  const pointerSel = hotspots
    .map((h) => `[data-label="${cssEscapeAttr(h.label)}"]`)
    .join(", ");
  const activeGroupSel = activeLabels
    .map((l) => `[data-label="${cssEscapeAttr(l)}"]`)
    .join(", ");
  const activeRectSel = activeLabels
    .map((l) => `[data-label="${cssEscapeAttr(l)}"] > rect`)
    .join(", ");

  const rules: string[] = [
    `text, tspan { font-family: ${UI_FONT}; }`,
  ];
  if (pointerSel) {
    rules.push(`${pointerSel}, ${pointerSel} * { cursor: pointer; }`);
  }
  if (activeRectSel) {
    rules.push(
      `${activeRectSel} { stroke: ${accent} !important; stroke-width: 2.5 !important; }`,
    );
  }
  if (activeGroupSel) {
    rules.push(
      `${activeGroupSel} > rect:first-of-type { fill: color-mix(in srgb, ${accent} 18%, var(--_node-fill, transparent)) !important; }`,
    );
  }
  if (rules.length === 0) return svg;

  const style = `<style data-arch-hotspot-chrome>${rules.join("\n")}</style>`;
  return svg.replace(/<svg([^>]*)>/, `<svg$1>${style}`);
}

export default function MapView() {
  const theme = useHostTheme();
  const dispatch = useCanvasAction();
  const [focus, setFocus] = useCanvasState<Focus>("focus", {
    kind: "node",
    id: PATH[0],
  });
  const [view, setView] = useCanvasState<View>("view", {
    x: 0,
    y: 0,
    zoom: 1,
  });
  const [activeId, setActiveId] = useCanvasState(
    "archDiagram",
    ARCH_DIAGRAMS[0].id,
  );
  const [sidebarW, setSidebarW] = useCanvasState(
    "sidebarW",
    DEFAULT_SIDEBAR_W,
  );
  const [sidebarOpen, setSidebarOpen] = useCanvasState("sidebarOpen", true);
  const [treeW, setTreeW] = useCanvasState("treeW", DEFAULT_TREE_W);
  const [dragging, setDragging] = useState(false);
  const [overHotspot, setOverHotspot] = useState(false);
  const dragOriginRef = useRef<{
    px: number;
    py: number;
    vx: number;
    vy: number;
  } | null>(null);
  const didPanRef = useRef(false);
  const downTargetRef = useRef<Element | null>(null);
  const [resizingW, setResizingW] = useState(false);
  const [sidebarResizeHot, setSidebarResizeHot] = useState(false);
  const resizeWRef = useRef<{ px: number; width: number } | null>(null);
  const [resizingTreeW, setResizingTreeW] = useState(false);
  const [treeResizeHot, setTreeResizeHot] = useState(false);
  const resizeTreeWRef = useRef<{ px: number; width: number } | null>(null);
  const [hoverPaths, setHoverPaths] = useState<string[]>([]);
  const [filePreview, setFilePreview] = useState<FileRef | null>(null);
  const [shellH, setShellH] = useState(
    typeof window !== "undefined" ? window.innerHeight : 800,
  );

  useEffect(() => {
    function onResize() {
      setShellH(window.innerHeight);
    }
    window.addEventListener("resize", onResize);
    return () => window.removeEventListener("resize", onResize);
  }, []);

  /** Lock page scroll — map is a single fixed viewport (CanvasShell + body). */
  useEffect(() => {
    const html = document.documentElement;
    const body = document.body;
    const root = document.getElementById("root");
    const prev = {
      htmlOverflow: html.style.overflow,
      htmlHeight: html.style.height,
      bodyOverflow: body.style.overflow,
      bodyHeight: body.style.height,
      bodyMargin: body.style.margin,
      rootOverflow: root?.style.overflow ?? "",
      rootHeight: root?.style.height ?? "",
    };
    html.style.overflow = "hidden";
    html.style.height = "100%";
    body.style.overflow = "hidden";
    body.style.height = "100%";
    body.style.margin = "0";
    if (root) {
      root.style.overflow = "hidden";
      root.style.height = "100%";
    }
    return () => {
      html.style.overflow = prev.htmlOverflow;
      html.style.height = prev.htmlHeight;
      body.style.overflow = prev.bodyOverflow;
      body.style.height = prev.bodyHeight;
      body.style.margin = prev.bodyMargin;
      if (root) {
        root.style.overflow = prev.rootOverflow;
        root.style.height = prev.rootHeight;
      }
    };
  }, []);

  const panelH = Math.max(0, shellH - OVERLAY_INSET * 2);

  const mapFiles = useMemo(
    () =>
      collectAllMapPaths().map((absPath) => ({
        absPath,
        relPath: relPath(absPath),
      })),
    [],
  );

  const diagram =
    ARCH_DIAGRAMS.find((d) => d.id === activeId) ?? ARCH_DIAGRAMS[0];
  const archWorld = svgWorldSize(diagram.svg);
  const snakeOffsetY = archWorld.h + ARCH_SNAKE_GAP;

  const activeLabels = useMemo(
    () =>
      diagram.hotspots
        .filter((h) => {
          if (h.nodeId && focus.kind === "node") return focus.id === h.nodeId;
          if (h.edgeKey && focus.kind === "edge") return focus.key === h.edgeKey;
          return false;
        })
        .map((h) => h.label),
    [diagram.hotspots, focus],
  );

  const cameraSvg = useMemo(
    () =>
      svgWithHotspotChrome(
        svgForCamera(diagram.svg, archWorld.w, archWorld.h),
        diagram.hotspots,
        activeLabels,
        theme.accent.primary,
      ),
    [
      diagram.svg,
      diagram.hotspots,
      archWorld.w,
      archWorld.h,
      activeLabels,
      theme.accent.primary,
    ],
  );

  function previewFiles(refs: FileRef[]) {
    setHoverPaths([...new Set(refs.map((r) => relPath(r.path)))]);
  }

  function clearPreview() {
    setHoverPaths([]);
  }

  function previewFile(ref: FileRef) {
    setFilePreview(ref);
  }

  const edgeMeta = new Map(
    EDGES.map((e) => [edgeKey(e.from, e.to), e] as const),
  );
  const layout = layoutWrappedPath(PATH);
  const nodeById = new Map(layout.nodes.map((n) => [n.id, n]));
  const laidEdges = buildPathEdges(layout.nodes, edgeMeta);

  const worldW = Math.max(archWorld.w + PAD, layout.width);
  const worldH = archWorld.h + ARCH_SNAKE_GAP + layout.height;

  const selectedNode =
    focus.kind === "node"
      ? (NODES.find((n) => n.id === focus.id) ?? NODES[0])
      : null;
  const selectedEdge =
    focus.kind === "edge" ? (edgeMeta.get(focus.key) ?? null) : null;
  const selectedEntity = selectedEdge ?? selectedNode ?? NODES[0];
  const selectedPaths = [
    ...new Set(collectFiles(selectedEntity).map((f) => relPath(f.path))),
  ];
  const pathIndex = selectedNode ? PATH.indexOf(selectedNode.id) : -1;
  const typeScale = sidebarType(sidebarW);

  function selectNode(id: string) {
    setFocus({ kind: "node", id });
    setSidebarOpen(true);
  }

  function selectEdge(key: string) {
    setFocus({ kind: "edge", key });
    setSidebarOpen(true);
  }

  function activateHotspot(h: ArchHotspot) {
    if (h.nodeId) selectNode(h.nodeId);
    else if (h.edgeKey) selectEdge(h.edgeKey);
  }

  function hitFromEvent(target: Element): ArchHotspot | null {
    const labeled = target.closest(
      "[data-label], .node, .actor, .class-node",
    );
    const fromAttr = labeled?.getAttribute("data-label")?.trim();
    const fromText = target.closest("text, tspan")?.textContent?.trim();
    const label = fromAttr || fromText;
    if (!label) return null;
    return (
      diagram.hotspots.find(
        (h) => label === h.label || label.includes(h.label),
      ) ?? null
    );
  }

  function updateHoverCursor(clientX: number, clientY: number) {
    if (dragOriginRef.current) {
      setOverHotspot(false);
      return;
    }
    const under = document.elementFromPoint(clientX, clientY);
    setOverHotspot(!!(under && hitFromEvent(under)));
  }

  function panStartBlocked(target: Element): boolean {
    return !!target.closest(
      "[data-map-node], [data-map-edge], [data-sidebar-resize], [data-tree-resize], [data-map-sidebar], [data-map-tree]",
    );
  }

  function openInIde(ref: FileRef) {
    const { start, end } = highlightRange(ref);
    dispatch({
      type: "openFile",
      path: ref.path,
      ...(start != null
        ? {
            selection: {
              startLineNumber: start,
              startColumn: 1,
              endLineNumber: end ?? start,
              endColumn: 1,
            },
          }
        : {}),
    });
  }

  function go(delta: number) {
    const base =
      focus.kind === "node" ? PATH.indexOf(focus.id) : Math.max(0, pathIndex);
    const next = PATH[base + delta];
    if (next) selectNode(next);
  }

  function setZoom(next: number) {
    setView((v) => ({ ...v, zoom: clamp(next, MIN_ZOOM, MAX_ZOOM) }));
  }

  function fit() {
    setView({ x: 0, y: 0, zoom: 1 });
  }

  const sidebarTitle =
    selectedEdge != null
      ? `${selectedEdge.label}: ${selectedEdge.from} → ${selectedEdge.to}`
      : (selectedNode?.label ?? "");
  const sidebarBody = selectedEdge?.body ?? selectedNode?.body ?? [];

  const viewportStyle: CSSProperties = {
    position: "absolute",
    inset: 0,
    overflow: "hidden",
    backgroundColor: theme.bg.editor,
    backgroundImage: `radial-gradient(${theme.stroke.tertiary} 1px, transparent 1px)`,
    backgroundSize: "18px 18px",
    cursor: dragging ? "grabbing" : overHotspot ? "pointer" : "grab",
    userSelect: "none",
    fontFamily: UI_FONT,
    WebkitFontSmoothing: "antialiased",
    MozOsxFontSmoothing: "grayscale",
  };

  const worldStyle: CSSProperties = {
    position: "absolute",
    left: 0,
    top: 0,
    width: worldW,
    height: worldH,
    transform: `translate(${view.x}px, ${view.y}px) scale(${view.zoom})`,
    transformOrigin: "0 0",
  };

  return (
    <div
      data-map-shell
      style={{
        // Escape CanvasShell page padding so the diagram is true edge-to-edge.
        position: "fixed",
        inset: 0,
        width: "100%",
        height: "100%",
        overflow: "hidden",
        overscrollBehavior: "none",
        padding: 0,
        margin: 0,
        zIndex: 1,
        fontFamily: UI_FONT,
        WebkitFontSmoothing: "antialiased",
        MozOsxFontSmoothing: "grayscale",
        textRendering: "optimizeLegibility",
      }}
    >
      <style dangerouslySetInnerHTML={{ __html: SIDEBAR_SCROLLBAR_CSS }} />
      <div
        data-map-viewport
        style={viewportStyle}
        onPointerDown={(e) => {
          const target = e.target as Element;
          if (panStartBlocked(target)) return;
          didPanRef.current = false;
          downTargetRef.current = target;
          dragOriginRef.current = {
            px: e.clientX,
            py: e.clientY,
            vx: view.x,
            vy: view.y,
          };
          setOverHotspot(false);
          setDragging(true);
          (e.currentTarget as HTMLElement).setPointerCapture(e.pointerId);
        }}
        onPointerMove={(e) => {
          const origin = dragOriginRef.current;
          if (!origin) {
            updateHoverCursor(e.clientX, e.clientY);
            return;
          }
          const dx = e.clientX - origin.px;
          const dy = e.clientY - origin.py;
          if (Math.abs(dx) > 3 || Math.abs(dy) > 3) didPanRef.current = true;
          setView({
            ...view,
            x: origin.vx + dx,
            y: origin.vy + dy,
          });
        }}
        onPointerUp={(e) => {
          try {
            (e.currentTarget as HTMLElement).releasePointerCapture(e.pointerId);
          } catch {
            /* already released */
          }
          if (!didPanRef.current) {
            const under = document.elementFromPoint(e.clientX, e.clientY);
            const hit =
              (under ? hitFromEvent(under) : null) ??
              (downTargetRef.current
                ? hitFromEvent(downTargetRef.current)
                : null);
            if (hit) activateHotspot(hit);
          }
          dragOriginRef.current = null;
          downTargetRef.current = null;
          didPanRef.current = false;
          setDragging(false);
          updateHoverCursor(e.clientX, e.clientY);
        }}
        onPointerLeave={() => setOverHotspot(false)}
        onWheel={(e) => {
          if (!e.ctrlKey && !e.metaKey) return;
          e.preventDefault();
          const delta = e.deltaY > 0 ? -0.08 : 0.08;
          setZoom(view.zoom + delta);
        }}
      >
        <div style={worldStyle}>
          <div
            data-arch-world
            style={{
              position: "absolute",
              left: 0,
              top: 0,
              width: archWorld.w,
              height: archWorld.h,
              padding: 0,
              boxSizing: "content-box",
            }}
            dangerouslySetInnerHTML={{ __html: cameraSvg }}
          />
          <div
            style={{
              position: "absolute",
              left: 0,
              top: snakeOffsetY,
              width: layout.width,
              height: layout.height,
            }}
          >
            <svg
              width={layout.width}
              height={layout.height}
              style={{ position: "absolute", inset: 0, overflow: "visible" }}
            >
              <defs>
                <marker
                  id="arrow"
                  markerWidth="8"
                  markerHeight="8"
                  refX="7"
                  refY="4"
                  orient="auto"
                >
                  <path
                    d="M0,0 L8,4 L0,8 Z"
                    fill={theme.stroke.secondary}
                  />
                </marker>
                <marker
                  id="arrow-active"
                  markerWidth="8"
                  markerHeight="8"
                  refX="7"
                  refY="4"
                  orient="auto"
                >
                  <path
                    d="M0,0 L8,4 L0,8 Z"
                    fill={theme.accent.primary}
                  />
                </marker>
              </defs>
              {laidEdges.map((e) => {
                const active =
                  focus.kind === "edge"
                    ? focus.key === e.key
                    : focus.kind === "node" &&
                      (e.from === focus.id || e.to === focus.id);
                const d = edgePath(e);
                return (
                  <g
                    key={e.key}
                    data-map-edge
                    onClick={(ev) => {
                      ev.stopPropagation();
                      selectEdge(e.key);
                    }}
                    onMouseEnter={() => {
                      const meta = edgeMeta.get(e.key);
                      if (meta) previewFiles(collectFiles(meta));
                    }}
                    onMouseLeave={clearPreview}
                    style={{ cursor: "pointer" }}
                  >
                    <path
                      d={d}
                      fill="none"
                      stroke="transparent"
                      strokeWidth={18}
                    />
                    <path
                      d={d}
                      fill="none"
                      stroke={
                        active ? theme.accent.primary : theme.stroke.secondary
                      }
                      strokeWidth={active ? 2.5 : 1.75}
                      markerEnd={
                        active ? "url(#arrow-active)" : "url(#arrow)"
                      }
                    />
                    {e.label ? (
                      <g>
                        <rect
                          x={
                            e.labelX - Math.max(30, e.label.length * 3.6 + 10)
                          }
                          y={e.labelY - 10}
                          width={Math.max(60, e.label.length * 7.2 + 20)}
                          height={18}
                          rx={4}
                          fill={theme.bg.editor}
                          stroke={
                            active
                              ? theme.accent.primary
                              : theme.stroke.tertiary
                          }
                          strokeWidth={1}
                        />
                        <text
                          x={e.labelX}
                          y={e.labelY + 3}
                          textAnchor="middle"
                          fill={
                            active
                              ? theme.accent.primary
                              : theme.text.secondary
                          }
                          fontSize={11}
                          fontFamily={UI_FONT}
                        >
                          {e.label}
                        </text>
                      </g>
                    ) : null}
                  </g>
                );
              })}
            </svg>

            {NODES.map((n, i) => {
              const pos = nodeById.get(n.id);
              if (!pos) return null;
              const isSelected = focus.kind === "node" && focus.id === n.id;
              return (
                <div
                  key={n.id}
                  data-map-node
                  onClick={() => selectNode(n.id)}
                  onMouseEnter={() => previewFiles(collectFiles(n))}
                  onMouseLeave={clearPreview}
                  style={{
                    position: "absolute",
                    left: pos.x,
                    top: pos.y,
                    width: NODE_W,
                    height: NODE_H,
                    boxSizing: "border-box",
                    padding: 12,
                    display: "flex",
                    flexDirection: "column",
                    gap: 8,
                    borderRadius: 8,
                    cursor: "pointer",
                    background: isSelected
                      ? theme.fill.tertiary
                      : theme.bg.elevated,
                    border: `1.5px solid ${
                      isSelected
                        ? theme.accent.primary
                        : theme.stroke.secondary
                    }`,
                  }}
                >
                  <Row gap={8} align="center">
                    <Pill size="sm" active={isSelected}>
                      {i + 1}
                    </Pill>
                    <Text weight="semibold" size="small">
                      {n.label}
                    </Text>
                  </Row>
                  <Text
                    size="small"
                    tone="secondary"
                    style={{ lineHeight: "1.35" }}
                  >
                    {richInline(n.teaser)}
                  </Text>
                </div>
              );
            })}
          </div>
        </div>
      </div>

      <div
        data-map-toolbar
        style={{
          position: "absolute",
          left: 0,
          right: 0,
          bottom: 16,
          zIndex: 11,
          pointerEvents: "none",
          display: "flex",
          justifyContent: "center",
        }}
      >
        <Card
          style={{
            pointerEvents: "auto",
            padding: "10px 14px",
          }}
        >
          <Row gap={8} align="center" wrap>
            {ARCH_DIAGRAMS.length > 1 ? (
              <>
                <Grid columns={ARCH_DIAGRAMS.length} gap={8}>
                  {ARCH_DIAGRAMS.map((d) => (
                    <Button
                      key={d.id}
                      variant={d.id === diagram.id ? "primary" : "secondary"}
                      onClick={() => {
                        setActiveId(d.id);
                        fit();
                      }}
                    >
                      {d.title}
                    </Button>
                  ))}
                </Grid>
                <Divider
                  style={{ width: 1, height: 20, alignSelf: "center" }}
                />
              </>
            ) : null}
            <IconButton
              title="Zoom out"
              style={TOOLBAR_ICON_BTN}
              onClick={() => setZoom(view.zoom - 0.15)}
            >
              <ZoomOutIcon />
            </IconButton>
            <IconButton
              title="Zoom in"
              style={TOOLBAR_ICON_BTN}
              onClick={() => setZoom(view.zoom + 0.15)}
            >
              <ZoomInIcon />
            </IconButton>
            <IconButton title="Fit" style={TOOLBAR_ICON_BTN} onClick={fit}>
              <FitIcon />
            </IconButton>
            <Text size="small" tone="tertiary">
              {Math.round(view.zoom * 100)}%
            </Text>
            <Divider style={{ width: 1, height: 20, alignSelf: "center" }} />
            <IconButton
              title="Previous step"
              style={TOOLBAR_ICON_BTN}
              disabled={pathIndex <= 0 && focus.kind === "node"}
              onClick={() => go(-1)}
            >
              <ChevronLeftIcon />
            </IconButton>
            <Pill>
              {focus.kind === "node"
                ? `${pathIndex + 1} / ${PATH.length}`
                : "edge"}
            </Pill>
            <IconButton
              title="Next step"
              style={TOOLBAR_ICON_BTN}
              disabled={
                focus.kind === "node" ? pathIndex >= PATH.length - 1 : false
              }
              onClick={() => go(1)}
            >
              <ChevronRightIcon />
            </IconButton>
            <Spacer />
            {!sidebarOpen ? (
              <IconButton
                title="Open details"
                style={TOOLBAR_ICON_BTN}
                onClick={() => setSidebarOpen(true)}
              >
                <SidebarIcon />
              </IconButton>
            ) : null}
          </Row>
        </Card>
      </div>

      {sidebarOpen ? (
        <div
          data-map-sidebar
          style={{
            position: "absolute",
            left: OVERLAY_INSET,
            top: OVERLAY_INSET,
            bottom: OVERLAY_INSET,
            zIndex: 10,
            width: sidebarW,
            boxSizing: "border-box",
            fontFamily: UI_FONT,
          }}
        >
          <Card
            style={{
              width: "100%",
              height: "100%",
              display: "flex",
              flexDirection: "column",
            }}
          >
            <CardHeader
              trailing={
                <IconButton
                  title="Close details"
                  style={TOOLBAR_ICON_BTN}
                  onClick={() => setSidebarOpen(false)}
                >
                  <CloseIcon />
                </IconButton>
              }
            >
              {sidebarTitle}
            </CardHeader>
            <CardBody
              style={{
                padding: 0,
                flex: 1,
                minHeight: 0,
                display: "flex",
                flexDirection: "column",
                overflow: "hidden",
              }}
            >
              <div
                data-map-sidebar-scroll
                style={{
                  padding: typeScale.pad,
                  overflow: "auto",
                  flex: 1,
                  minHeight: 0,
                  display: "flex",
                  flexDirection: "column",
                  gap: typeScale.gap,
                }}
              >
                {renderDocBlocks(
                  sidebarBody,
                  typeScale,
                  theme,
                  previewFile,
                  previewFiles,
                  clearPreview,
                )}
              </div>
            </CardBody>
          </Card>
          <div
            data-sidebar-resize
            title="Drag to resize sidebar"
            onMouseEnter={() => setSidebarResizeHot(true)}
            onMouseLeave={() => {
              if (!resizingW) setSidebarResizeHot(false);
            }}
            onPointerDown={(e) => {
              e.preventDefault();
              e.stopPropagation();
              (e.currentTarget as HTMLElement).setPointerCapture(e.pointerId);
              setResizingW(true);
              setSidebarResizeHot(true);
              resizeWRef.current = { px: e.clientX, width: sidebarW };
            }}
            onPointerMove={(e) => {
              const origin = resizeWRef.current;
              if (!origin) return;
              setSidebarW(
                clamp(
                  origin.width + (e.clientX - origin.px),
                  MIN_SIDEBAR_W,
                  MAX_SIDEBAR_W,
                ),
              );
            }}
            onPointerUp={(e) => {
              (e.currentTarget as HTMLElement).releasePointerCapture(
                e.pointerId,
              );
              setResizingW(false);
              setSidebarResizeHot(false);
              resizeWRef.current = null;
            }}
            style={{
              position: "absolute",
              top: 0,
              right: 0,
              bottom: 0,
              width: 8,
              cursor: "ew-resize",
              background:
                resizingW || sidebarResizeHot
                  ? theme.fill.secondary
                  : "transparent",
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
            }}
          >
            <div
              style={{
                width: 2,
                height: 28,
                borderRadius: 1,
                background: theme.stroke.primary,
                opacity: resizingW || sidebarResizeHot ? 1 : 0,
              }}
            />
          </div>
        </div>
      ) : null}

      <div
        data-map-tree
        style={{
          position: "absolute",
          right: OVERLAY_INSET,
          top: OVERLAY_INSET,
          bottom: OVERLAY_INSET,
          zIndex: 10,
          width: treeW,
          boxSizing: "border-box",
          fontFamily: UI_FONT,
        }}
      >
        <div
          data-tree-resize
          title="Drag to resize file tree"
          onMouseEnter={() => setTreeResizeHot(true)}
          onMouseLeave={() => {
            if (!resizingTreeW) setTreeResizeHot(false);
          }}
          onPointerDown={(e) => {
            e.preventDefault();
            e.stopPropagation();
            (e.currentTarget as HTMLElement).setPointerCapture(e.pointerId);
            setResizingTreeW(true);
            setTreeResizeHot(true);
            resizeTreeWRef.current = { px: e.clientX, width: treeW };
          }}
          onPointerMove={(e) => {
            const origin = resizeTreeWRef.current;
            if (!origin) return;
            setTreeW(
              clamp(
                origin.width - (e.clientX - origin.px),
                MIN_TREE_W,
                MAX_TREE_W,
              ),
            );
          }}
          onPointerUp={(e) => {
            (e.currentTarget as HTMLElement).releasePointerCapture(
              e.pointerId,
            );
            setResizingTreeW(false);
            setTreeResizeHot(false);
            resizeTreeWRef.current = null;
          }}
          style={{
            position: "absolute",
            top: 0,
            left: 0,
            bottom: 0,
            width: 8,
            zIndex: 2,
            cursor: "ew-resize",
            background:
              resizingTreeW || treeResizeHot
                ? theme.fill.secondary
                : "transparent",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
          }}
        >
          <div
            style={{
              width: 2,
              height: 28,
              borderRadius: 1,
              background: theme.stroke.primary,
              opacity: resizingTreeW || treeResizeHot ? 1 : 0,
            }}
          />
        </div>
        <Card
          style={{
            width: "100%",
            height: "100%",
            display: "flex",
            flexDirection: "column",
          }}
        >
          <CardHeader>Files in this map</CardHeader>
          <CardBody
            style={{
              padding: 0,
              flex: 1,
              minHeight: 0,
              overflow: "hidden",
            }}
          >
            <FileTreePanel
              files={mapFiles}
              selectedPaths={selectedPaths}
              hoverPaths={hoverPaths}
              theme={theme}
              height={panelH}
              width={treeW}
              previewFile={previewFile}
            />
          </CardBody>
        </Card>
      </div>

      {filePreview ? (
        <CodePreviewModal
          file={filePreview}
          theme={theme}
          onClose={() => setFilePreview(null)}
          onOpenInIde={openInIde}
        />
      ) : null}
    </div>
  );
}
